if (msg.topic === 'stall') {
    context.set('stalled', true);
    msg.payload = 'STALLED — no data for 60 s';
    return msg;
}

// Data frame from NtripClient — check whether we just recovered.
if (context.get('stalled')) {
    context.set('stalled', false);
    msg.payload = 'RECOVERED — NTRIP stream is flowing again';
    return msg;
}

// Stream is fine; no transition to report.
return null;
